  // ==================== Storage Stats ====================

  Map<String, dynamic> getStorageStats() {
    _ensureInitialized();
    final allKeys = _prefs.getKeys();
    final cacheKeys =
        allKeys.where((k) => k.startsWith(StorageKeys.cachePrefix)).length;
    final offlineKeys =
        allKeys.where((k) => k.startsWith(StorageKeys.offlineDataPrefix)).length;
    final otherKeys = allKeys.length - cacheKeys - offlineKeys;

    return {
      'totalKeys': allKeys.length,
      'cacheEntries': cacheKeys,
      'offlineEntries': offlineKeys,
      'otherEntries': otherKeys,
      'isAuthenticated': isAuthenticated,
      'hasUserProfile': getUserProfile() != null,
      'hasAppConfig': getAppConfig() != null,
      'lastSyncTime': getLastSyncTime()?.toIso8601String(),
