// Extension for easy access throughout the app
extension LocalStorageManagerExtension on LocalStorageManager {
  /// Quick check if the app has all necessary data for offline use
  bool get isReadyForOffline {
    return getUserProfile() != null && getAppConfig() != null;
  }

  /// Get a summary of all user preferences
  Map<String, dynamic> getAllPreferences() {
    return {
      'themeMode': getThemeMode(),
      'locale': getLocale(),
      'notificationsEnabled': areNotificationsEnabled(),
      'biometricEnabled': isBiometricEnabled(),
      'fontSize': getFontSize(),
      'autoPlayVideos': isAutoPlayVideosEnabled(),
      'downloadOverWifiOnly': isDownloadOverWifiOnly(),
    };
  }
}

// Usage example / initialization helper
class StorageInitializer {
  static Future<LocalStorageManager> init() async {
    final storage = LocalStorageManager.instance;
    await storage.initialize();

    // Clean expired cache on startup
    await storage.clearExpiredCache();

    return storage;
  }
}